    check_dict_case({"Name":"John", "Age":"36", "City":"Houston"}) should return False.
    check_dict_case({"STATE":"NC", "ZIP":"12345" }) should return True.
    """
    if not dict:
        return False
    case = None
    for key in dict:
        if not isinstance(key, str):
            return False
        if key.islower():
            if case is None:
                case = 'lower'
            elif case != 'lower':
                return False
        elif key.isupper():
            if case is None:
                case = 'upper'
            elif case != 'upper':
                return False
        else:
            return False
    return True

