from functools import lru_cache

@lru_cache(None)
def breakSum(n):
    """
    Returns the maximum sum obtainable by recursively breaking n into three parts:
    floor(n/2), floor(n/3), floor(n/4) and summing them, or keeping n as is.
    """
    if n == 0:
        return 0
    return max(n, breakSum(n // 2) + breakSum(n // 3) + breakSum(n // 4))

def set_left_most_unset_bit(n: int) -> int:
    """
    Set the leftmost unset bit in the binary representation of n.
    If all bits are set, return n unchanged.
    """
    if n == 0:
        return 1
    bit_len = n.bit_length()
    for pos in range(bit_len - 1, -1, -1):
        if (n >> pos) & 1 == 0:
            return n | (1 << pos)
    return n

