def eulerian_num(n, m):
    """Return the Eulerian number A(n, m)."""
    if m < 0 or m >= n:
        return 0
    if n == 1:
        return 1
    # DP table
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[1][0] = 1
    for i in range(2, n + 1):
        dp[i][0] = 1
        for j in range(1, i):
            dp[i][j] = (j + 1) * dp[i - 1][j] + (i - j) * dp[i - 1][j - 1]
    return dp[n][m]

