def max_sum_increasing_subseq(arr, n, i, k):
    """
    Returns the maximum sum of an increasing subsequence that includes arr[k]
    and uses only elements from indices 0..i (prefix up to i).
    """
    # dp[j] = max sum of increasing subsequence ending at arr[j] using only indices <= j
    dp = [0] * n
    for idx in range(i + 1):
        dp[idx] = arr[idx]
        for prev in range(idx):
            if arr[prev] < arr[idx]:
                dp[idx] = max(dp[idx], arr[idx] + dp[prev])

    # answer is arr[k] plus the best dp from prefix where arr[j] < arr[k]
    ans = arr[k]
    for j in range(i + 1):
        if arr[j] < arr[k]:
            ans = max(ans, arr[k] + dp[j])
    return ans

