def first_Missing_Positive(arr, n):
    """
    Find the first missing positive integer in the given list of size n.
    Uses cyclic sort to place each positive number x at index x-1.
    """
    i = 0
    while i < n:
        # If the current number is within the range [1, n] and not already at its correct position
        if 0 < arr[i] <= n and arr[arr[i] - 1] != arr[i]:
            # Swap to its correct position
            arr[arr[i] - 1], arr[i] = arr[i], arr[arr[i] - 1]
        else:
            i += 1

    # After sorting, the first index where arr[i] != i+1 is the missing positive
    for i in range(n):
        if arr[i] != i + 1:
            return i + 1

    # If all positions are correct, the missing positive is n+1
    return n + 1

