    # Check columns
    for col in range(n):
        if sum(matrix[row][col] for row in range(n)) != expected:
            return False
    # Check main diagonal
    if sum(matrix[i][i] for i in range(n)) != expected:
        return False
    # Check anti-diagonal
    if sum(matrix[i][n - 1 - i] for i in range(n)) != expected:
        return False
    return True

