def modified_encode(seq):
    """Return modified run-length encoding of seq."""
    if not seq:
        return []
    result = []
    current = seq[0]
    count = 1
    for i in range(1, len(seq)):
        if seq[i] == current:
            count += 1
        else:
            if count == 1:
                result.append(current)
            else:
                result.append([count, current])
            current = seq[i]
            count = 1
    # handle last run
    if count == 1:
        result.append(current)
    else:
        result.append([count, current])
    return result

