def no_of_subsequences(arr, k):
    n = len(arr)
    def dfs(idx, prod):
        if idx == n:
            return 1
        # skip current element
        res = dfs(idx + 1, prod)
        # include current element if product stays less than k
        if prod * arr[idx] < k:
            res += dfs(idx + 1, prod * arr[idx])
