import math

def get_Min_Squares(n):
    # 1. Check if n is a perfect square
    if math.isqrt(n) ** 2 == n:
        return 1

    # 2. Check if n can be expressed as sum of two squares
    for i in range(1, math.isqrt(n) + 1):
        remainder = n - i * i
        if math.isqrt(remainder) ** 2 == remainder:
            return 2

    # 3. Check Legendre's condition for three squares
    temp = n
    while temp % 4 == 0:
        temp //= 4
    if temp % 8 == 7:
        return 4

    # 4. Otherwise, it can be expressed as sum of three squares
    return 3

def sequence(n: int) -> int:
    """Return the n-th term of the Newman Conway sequence."""
    if n <= 0:
        raise ValueError("n must be a positive integer")
    # DP array, 1-indexed
    dp = [0] * (n + 1)
    dp[1] = 1
    if n >= 2:
        dp[2] = 1
    for i in range(3, n + 1):
        dp[i] = dp[dp[i - 1]] + dp[i - dp[i - 1]]
    return dp[n]

