                total += g // i
    return total

def empty_dit(d):
    """Return True if all dictionaries in the input are empty."""
    if isinstance(d, dict):
        return len(d) == 0
    if isinstance(d, list):
        return all(isinstance(item, dict) and len(item) == 0 for item in d)
    return False

def longest_common_subsequence(seq1, seq2, m, n):
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if seq1[i - 1] == seq2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])
    return dp[m][n]

def count_Odd_Squares(a, b):
    import math
    # floor sqrt of a
    start = math.isqrt(a)
    if start * start < a:
        start += 1  # ceil sqrt
    # floor sqrt of b
    end = math.isqrt(b)
    if end * end > b:
        end -= 1  # floor sqrt (should not happen, but safe)
    # count of perfect squares
    return max(0, end - start + 1)

def dig_let(s):
    """Return (number of digits, number of letters) in string s."""
    digits = 0
    letters = 0
    for ch in s:
        if ch.isdigit():
            digits += 1
        elif ch.isalpha():
            letters += 1
    return (digits, letters)

def remove_dirty_chars(s1, s2):
    """
    Remove characters from s1 that are present in s2.
    """
    s2_set = set(s2)
    return ''.join(ch for ch in s1 if ch not in s2_set)

def max_occurrences(lst):
    from collections import Counter
    if not lst:
        return None
    counts = Counter(lst)
    max_freq = max(counts.values())
    candidates = [item for item, freq in counts.items() if freq == max_freq]
    first_index = {val: i for i, val in enumerate(lst)}
    candidates.sort(key=lambda x: first_index[x])
    if len(candidates) == 1:
        return candidates[0]
    return tuple(candidates)

def highest_Power_of_2(n):
    """Return the highest power of 2 less than or equal to n."""
    if n <= 0:
        return 0
    # bit_length returns the number of bits required to represent n in binary, excluding the sign and leading zeros.
    # The highest power of 2 <= n is 2^(bit_length - 1)
    return 1 << (n.bit_length() - 1)

def reverse_vowels(s):
    vowels = set('aeiouAEIOU')
    vowel_list = [c for c in s if c in vowels]
    vowel_list.reverse()
    it = iter(vowel_list)
    return ''.join(next(it) if c in vowels else c for c in s)

def most_occurrences(strings):
    from collections import Counter
    counter = Counter()
    for s in strings:
        for word in s.split():
            counter[word] += 1
    if not counter:
        return ''
    return max(counter, key=counter.get)

def neg_nos(lst):
    """Return a tuple of negative numbers from the list, preserving order."""
    return tuple(x for x in lst if x < 0)

def first(arr, value, length):
    for i in range(length):
        if arr[i] == value:
            return i
    return -1

import math

def count_binary_seq(n):
    """Return the count of binary sequences of length 2n where the sum of the first n bits equals the sum of the last n bits."""
    return float(math.comb(2 * n, n))
